PREFIX co: <https://ontorag.dev/ns/commerce#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?orgName ?ceoName WHERE { ?org co:hasCEO ?ceo . ?org rdfs:label ?orgName . ?ceo rdfs:label ?ceoName . FILTER(LANG(?orgName) = 'en' && LANG(?ceoName) = 'en') }

PREFIX co: <https://ontorag.dev/ns/commerce#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(DISTINCT ?p) AS ?n) WHERE { ?p a ?cls . ?cls rdfs:subClassOf* co:ConsumerElectronics . }
